// Amiri (Regular) ? vendored Arabic font for jsPDF.
// Subset of Amiri-Regular.ttf (SIL OFL 1.1) to Latin + Arabic + Arabic
// presentation forms, with layout tables dropped (we pre-shape text in
// arabic-shaper.js). Registers itself as font "Amiri" on every jsPDF doc.
// Source: https://github.com/google/fonts/tree/main/ofl/amiri
(function (jsPDFAPI) {
  "use strict";
  var font = "";
  jsPDFAPI.events.push(["addFonts", function () {
    this.addFileToVFS("Amiri-Regular.ttf", font);
    this.addFont("Amiri-Regular.ttf", "Amiri", "normal");
  }]);
})(window.jspdf.jsPDF.API);
